/*
输入T
while遍历T--
	输入p、a、b、x、t 
	如果x==t
		输出1
	如果a==1
		t=((t-x)%p+p)%p
		如果t%gcd(b,p)
			输出-1
		否则
			如果(t*bsgs(b,p)+1)%p==0
				输出p
			否则
				输出(t*bsgs(b,p)+1)%p 
	否则如果a==0
		如果b==t
			输出2
		否则
			输出-1
	否则
		ans = bsgs(a, ((t - b * inv(1 - a, p)) % p + p) % p * inv(((x - b * inv(1 - a, p)) % p + p) % p, p), p) % p
		如果ans==-1
			输出-1
		否则
			输出ans+1 
*/
#include <bits/stdc++.h>
#define int long long
using namespace std;
int qpow (int a, int b, int p) {
	int res = 1;
	while (b) {
		if (b & 1) {
			res = res * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return res;
}
int BSGS (int a, int b, int p) {
	a %= p;
	b %= p;
//	if (b == 1) {
//		return 0;
//	}
	int m = ceil (sqrt (p));
	int t = b;
	unordered_map <int, int> mp;
	for (int j = 0; j < m; j++) {
		mp[t] = j;
		t = t * a % p;
	}
	int mi = qpow (a, m, p);
	t = 1;
	for (int i = 1; i <= m; i++) {
		t = t * mi % p;
		if (mp.count (t)) {
			return i * m - mp[t];
		}
	}
	return -1;
}
int bsgs (int x, int p) {
	return qpow (x, p - 2, p);
}
signed main() {
	int T;
	cin >> T; 
	while (T--) {
		int p, a, b, x, t;
		cin >> p >> a >> b >> x >> t;
		if (x == t) {
			cout << "1\n";
			continue;
		}
		if (a == 1) {
			t = ((t - x) % p + p) % p;
			if (t % __gcd (b, p)) {
				cout << "-1\n";
			} else {
				if ((t * bsgs (b, p) + 1) % p == 0) {
					cout << p << '\n';
				} else {
					cout << (t * bsgs (b, p) + 1) % p << '\n';
				}
			}
		} else if (a == 0) {
			if (b == t) {
				cout << "2\n";
			} else {
				cout << "-1\n";
			}
		} else {
			int ans = BSGS (a, ((t - b * bsgs (1 - a, p)) % p + p) % p * bsgs (((x - b * bsgs (1 - a, p)) % p + p) % p, p), p) % p;
			if (ans == -1) {
				cout << "-1\n";
			} else {
				cout << ans + 1 << '\n';
			}
		}
	}
	return 0;
}
